void BM_Extend(benchmark::State& state) {
  int len = state.range(0);
  std::string extension = TestString(len);
  absl::crc32c_t base = absl::crc32c_t{0xC99465AA};  // CRC32C of "Hello World"
  for (auto s : state) {
    benchmark::DoNotOptimize(base);
    benchmark::DoNotOptimize(extension);
    absl::crc32c_t crc = absl::ExtendCrc32c(base, extension);
    benchmark::DoNotOptimize(crc);
  }
}

void LevenbergMarquardtStrategy::StepAccepted(double step_quality) {
  CHECK_GT(step_quality, 0.0);
  radius_ =
      radius_ / std::max(1.0 / 3.0, 1.0 - pow(2.0 * step_quality - 1.0, 3));
  radius_ = std::min(max_radius_, radius_);
  decrease_factor_ = 2.0;
  reuse_diagonal_ = false;
}

void ArctanLoss::Evaluate(double s, double rho[3]) const {
  const double sum = 1 + s * s * b_;
  const double inv = 1 / sum;
  // 'sum' and 'inv' are always positive.
  rho[0] = a_ * atan2(s, a_);
  rho[1] = std::max(std::numeric_limits<double>::min(), inv);
  rho[2] = -2.0 * s * b_ * (inv * inv);
}

void BlockRandomAccessDiagonalMatrix::Invert() {
  auto& blocks = m_->row_blocks();
  const int num_blocks = blocks.size();
  ParallelFor(context_, 0, num_blocks, num_threads_, [this, blocks](int i) {
    auto& cell_info = layout_[i];
    auto& block = blocks[i];
    MatrixRef b(cell_info.values, block.size, block.size);
    b = b.selfadjointView<Eigen::Upper>().llt().solve(
        Matrix::Identity(block.size, block.size));
  });
}

ParkResult park(const Key key, D&& data, ToPark&& toPark, PreWait&& preWait) {
  return park_until(
      key,
      std::forward<D>(data),
      std::forward<ToPark>(toPark),
      std::forward<PreWait>(preWait),
      std::chrono::steady_clock::time_point::max());
}

auto callWithExtractedKey(Alloc& a, Func&& f, std::pair<U1, U2> const& p) {
  return callWithExtractedKey<KeyType, MappedType, UsableAsKey>(
      a,
      std::forward<Func>(f),
      std::piecewise_construct,
      std::forward_as_tuple(p.first),
      std::forward_as_tuple(p.second));
}

system_clock::time_point Timespec2Timepoint(gpr_timespec t) {
  if (gpr_time_cmp(t, gpr_inf_future(t.clock_type)) == 0) {
    return system_clock::time_point::max();
  }
  t = gpr_convert_clock_type(t, GPR_CLOCK_REALTIME);
  system_clock::time_point tp;
  tp += duration_cast<system_clock::time_point::duration>(seconds(t.tv_sec));
  tp +=
      duration_cast<system_clock::time_point::duration>(nanoseconds(t.tv_nsec));
  return tp;
}

cv::Mat calculateCrossPowerSpectrum(const cv::Mat& dft1, const cv::Mat& dft2)
{
    cv::Mat cps(dft1.rows, dft1.cols, dft1.type());
    if (dft1.type() == CV_32FC2)
        calculateCrossPowerSpectrum<float>(dft1, dft2, cps);
    else if (dft1.type() == CV_64FC2)
        calculateCrossPowerSpectrum<double>(dft1, dft2, cps);
    else
        CV_Error(cv::Error::StsNotImplemented, "Only CV_32FC2 and CV_64FC2 types are supported");
    return cps;
}

void ULID::copyTo(char* buffer) const
{
	Poco::UInt32 timeHi = Poco::ByteOrder::toNetwork(_timeHi);
	std::memcpy(buffer, &timeHi, 4);
	Poco::UInt16 timeLo = Poco::ByteOrder::toNetwork(_timeLo);
	std::memcpy(buffer + 4, &timeLo, 2);
	Poco::UInt16 randomHi = Poco::ByteOrder::toNetwork(_randomHi);
	std::memcpy(buffer + 6, &randomHi, 2);
	Poco::UInt64 randomLo = Poco::ByteOrder::toNetwork(_randomLo);
	std::memcpy(buffer + 8, &randomLo, 8);
}

const char* EpsCopyInputStream::ReadArrayFallback(const char* ptr,
                                                  absl::Span<char> out) {
  char* dst = out.data();
  return AppendSize(ptr, out.size(), [&dst](const char* p, int s) {
    memcpy(dst, p, s);
    dst += s;
  });
}

static bool IsWindowsAbsolutePath(absl::string_view text) {
#if defined(_WIN32) || defined(__CYGWIN__)
  return text.size() >= 3 && text[1] == ':' && absl::ascii_isalpha(text[0]) &&
         (text[2] == '/' || text[2] == '\\') && text.find_last_of(':') == 1;
#else
  return false;
#endif
}

[[nodiscard]] const char* EpsCopyInputStream::ReadArrayMaybeFlush(
    const char* ptr, absl::Span<char> out, SinkT& sink) {
  char* dst = out.data();
  return AdvancePtrMaybeFlush<char>(
      ptr, out.size(), sink, [&](absl::string_view view) {
        memcpy(dst, view.data(), view.size());
        dst += view.size();
        ABSL_DCHECK_LE(dst, out.data() + out.size());
        return true;
      });
}

